# ── Load data ──────────────────────────────────────────────────────────────────
@st.cache_data
def load_data():
    df = pd.read_csv(StringIO(DATA))
    df["record_date"] = pd.to_datetime(df["record_date"])
    df = df.sort_values("record_date").reset_index(drop=True)
    return df

@st.cache_data
def load_standardized_data():
    """Standardize all numeric columns to mean=0, sd=1.
    record_date is preserved as-is; non-numeric columns are skipped.
    """
    df = load_data()
    df_std = df.copy()
    numeric_cols = df.select_dtypes(include="number").columns.tolist()
    # Exclude fiscal year and calendar month — not metrics
    exclude = ["record_fiscal_year", "record_calendar_month"]
    cols_to_standardize = [c for c in numeric_cols if c not in exclude]
    for col in cols_to_standardize:
        mean = df[col].mean()
        sd = df[col].std()
        if sd > 0:  # avoid division by zero for constant columns
            df_std[col] = (df[col] - mean) / sd
        else:
            df_std[col] = 0.0
    return df_std

@st.cache_data
def load_gdp_deflated_data():
    # Adjust all numeric metric columns to real dollars using the gdp_deflator
    # column already embedded in the data.
    #
    # Formula: real_value = nominal_value * (base_deflator / row_deflator)
    # Base: mean gdp_deflator across all rows with a valid deflator value.
    # gdp_deflator itself is excluded from adjustment and dropped from output
    # since it is the instrument, not a metric to be plotted.
    df = load_data()
    df_real = df.copy()

    # Base deflator: 2026 Q1 (January, February, or March 2026)
    # Match rows where record_date falls in Q1 2026 and extract the deflator
    q1_2026_mask = (
        (df["record_date"].dt.year == 2026) &
        (df["record_date"].dt.month <= 3)
    )
    q1_2026_deflators = df.loc[q1_2026_mask, "gdp_deflator"].dropna()

    if q1_2026_deflators.empty:
        # Fallback: use most recent available deflator if 2026 Q1 not in data
        valid_deflators = df["gdp_deflator"].dropna()
        if valid_deflators.empty:
            return df  # no deflator data at all, return raw
        base_deflator = valid_deflators.iloc[-1]
    else:
        # All Q1 2026 rows should share the same deflator value -- take the first
        base_deflator = q1_2026_deflators.iloc[0]

    # Identify columns to adjust -- numeric, excluding metadata and gdp_deflator
    exclude = ["record_fiscal_year", "record_calendar_month", "gdp_deflator"]
    numeric_cols = df.select_dtypes(include="number").columns.tolist()
    cols_to_adjust = [c for c in numeric_cols if c not in exclude]

    # Apply row-wise deflation using vectorized operations
    for col in cols_to_adjust:
        deflator_ratio = base_deflator / df["gdp_deflator"]
        df_real[col] = df[col] * deflator_ratio

    # Drop gdp_deflator -- it is not a plottable metric
    df_real = df_real.drop(columns=["gdp_deflator"])

    return df_real

@st.cache_data
def load_dictionary():
    dict_df = pd.read_csv(StringIO(DICTIONARY))
    # Exclude metadata variables and gdp_deflator (instrument, not a plottable metric)
    dict_df = dict_df[dict_df["group"] != "metadata"].reset_index(drop=True)
    dict_df = dict_df[dict_df["variable"] != "gdp_deflator"].reset_index(drop=True)
    return dict_df

df_raw = load_data()
df_std = load_standardized_data()
df_gdp = load_gdp_deflated_data()
dict_df = load_dictionary()

# ── App header ─────────────────────────────────────────────────────────────────
st.title("📊 Monthly Treasury Statement Dashboard (Draft)")
st.caption("U.S. Treasury — Monthly Financial Data Explorer (Draft)")

# ══════════════════════════════════════════════════════════════════════════════
# SIDEBAR — Selectors
# ══════════════════════════════════════════════════════════════════════════════
with st.sidebar:
    st.header("Select Variables")

    # ── Data mode: Raw or Standardized ────────────────────────────────────────
    st.markdown("---")
    data_mode = st.radio(
        "Data:",
        options=["Raw", "Standardized (z-score)", "GDP-Deflated"],
        horizontal=False,
    )
    if data_mode == "Raw":
        df = df_raw
    elif data_mode == "Standardized (z-score)":
        df = df_std
    else:
        df = df_gdp

    st.markdown("---")

    # ── Filter mode: Group or MTS Table ───────────────────────────────────────
    filter_mode = st.radio(
        "Filter by:",
        options=["Group", "MTS Table"],
        horizontal=True,
    )

    # ── Group dropdown ─────────────────────────────────────────────────────────
    if filter_mode == "Group":
        groups = dict_df["group"].unique().tolist()
        selected_filter = st.selectbox(
            "Select Group",
            options=groups,
            index=groups.index("summary"),   # default to summary
        )
        filtered_vars = dict_df[dict_df["group"] == selected_filter]["variable"].tolist()

    # ── MTS Table dropdown ─────────────────────────────────────────────────────
    else:
        tables = sorted(dict_df["mts_table"].unique().tolist(), key=str)
        selected_filter = st.selectbox(
            "Select MTS Table",
            options=tables,
            format_func=lambda x: f"Table {x}",
        )
        filtered_vars = dict_df[dict_df["mts_table"] == selected_filter]["variable"].tolist()

    # ── Variable checkboxes with Select All ───────────────────────────────────
    st.markdown("---")
    st.subheader("Variables")

    # Select All toggle
    select_all = st.checkbox("Select All", value=True)

    # If Select All is checked and there are more than 6 variables,
    # pre-select only the first 6 in data column order before rendering
    if select_all and len(filtered_vars) > 6:
        all_cols = [c for c in df.columns if c in filtered_vars]
        default_selected = set(all_cols[:6])
        st.caption("⚠️ Max 6 variables shown. First 6 pre-selected.")
    else:
        default_selected = set(filtered_vars) if select_all else set()

    # Render one checkbox per variable — checked state reflects the 6-var limit
    selected_vars = []
    for var in filtered_vars:
        checked = st.checkbox(var, value=(var in default_selected), key=f"cb_{var}")
        if checked:
            selected_vars.append(var)

    # Final safety cap — if user manually checks more than 6
    if len(selected_vars) > 6:
        all_cols = [c for c in df.columns if c in selected_vars]
        selected_vars = all_cols[:6]
        st.caption("⚠️ Max 6 variables. Showing first 6 checked.")

# ══════════════════════════════════════════════════════════════════════════════
# DATE RANGE SLIDER
# ══════════════════════════════════════════════════════════════════════════════
min_date = df["record_date"].min()
max_date = df["record_date"].max()

# Convert to plain Python dates for the slider (Streamlit requires this)
min_d = min_date.date()
max_d = max_date.date()

st.markdown("### Date Range")
date_range = st.slider(
    label="Select date range",
    min_value=min_d,
    max_value=max_d,
    value=(min_d, max_d),        # default: full range selected
    format="MMM YYYY",           # display as e.g. "Jan 2021"
)

# Filter the dataframe to the selected date range
start_date, end_date = date_range
df_filtered = df[
    (df["record_date"].dt.date >= start_date) &
    (df["record_date"].dt.date <= end_date)
].copy()

# ══════════════════════════════════════════════════════════════════════════════
# FACETED LINE CHARTS
# ══════════════════════════════════════════════════════════════════════════════

# ── Chart title reflecting active mode and date range ─────────────────────────
is_standardized = data_mode == "Standardized (z-score)"
is_gdp_deflated = data_mode == "GDP-Deflated"
if is_standardized:
    mode_label = "Z-Score (Standardized)"
elif is_gdp_deflated:
    mode_label = "Real Dollars (GDP-Deflated, 2026Q1 dollars)"
else:
    mode_label = "USD (Nominal)"
chart_title = (
    f"MTS Data — {start_date.strftime('%b %Y')} to {end_date.strftime('%b %Y')}  "
    f"| {mode_label}"
)
st.markdown(f"### {chart_title}")

if not selected_vars:
    st.warning("No variables selected. Please select at least one variable in the sidebar.")

elif df_filtered.empty:
    st.warning("No data in the selected date range.")

else:
    n = len(selected_vars)

    # ── Color palette — one color per variable ────────────────────────────────
    colors = [
        "#1f77b4", "#ff7f0e", "#2ca02c",
        "#d62728", "#9467bd", "#8c564b",
    ]

    if is_standardized:
        # ── STANDARDIZED MODE: all variables on a single overlaid chart ───────
        fig = go.Figure()

        for i, var in enumerate(selected_vars):
            fig.add_trace(
                go.Scatter(
                    x=df_filtered["record_date"],
                    y=df_filtered[var],
                    mode="lines+markers",
                    name=var,
                    line=dict(width=2, color=colors[i % len(colors)]),
                    marker=dict(size=4, color=colors[i % len(colors)]),
                    showlegend=True,
                    hovertemplate=(
                        "<b>%{x|%b %Y}</b><br>"
                        + f"{var}: %{{y:.2f}}σ"
                        + "<extra></extra>"
                    ),
                )
            )

        fig.update_layout(
            yaxis=dict(
                tickformat=".1f",
                ticksuffix="σ",
                zeroline=True,
                zerolinecolor="#cccccc",
                zerolinewidth=1,
                tickfont=dict(color="#000000"),
            ),
            legend=dict(
                orientation="h",
                yanchor="bottom",
                y=1.02,
                xanchor="left",
                x=0,
                font=dict(color="#000000"),
            ),
        )

    else:
        # ── RAW / GDP-DEFLATED MODE: faceted charts, one per variable ─────────
        n_cols = 2
        n_rows = (n + 1) // 2   # ceiling division: e.g. 5 vars → 3 rows

        fig = make_subplots(
            rows=n_rows,
            cols=n_cols,
            subplot_titles=selected_vars,
            vertical_spacing=0.15,
            horizontal_spacing=0.10,
        )

        for i, var in enumerate(selected_vars):
            row = i // n_cols + 1
            col = i % n_cols + 1

            fig.add_trace(
                go.Scatter(
                    x=df_filtered["record_date"],
                    y=df_filtered[var],
                    mode="lines+markers",
                    name=var,
                    line=dict(width=2, color=colors[i % len(colors)]),
                    marker=dict(size=4, color=colors[i % len(colors)]),
                    showlegend=False,
                    hovertemplate=(
                        "<b>%{x|%b %Y}</b><br>"
                        + f"{var}: %{{y:$.3s}}"
                        + "<extra></extra>"
                    ),
                ),
                row=row,
                col=col,
            )

        # Dollar formatting on all y-axes
        for i in range(1, n + 1):
            axis_key = f"yaxis{i if i > 1 else ''}"
            fig.update_layout(**{
                axis_key: dict(tickformat="$.3s")
            })

    # ── Subplot title font (faceted mode only) ───────────────────────────────
    if not is_standardized:
        for annotation in fig.layout.annotations:
            annotation.font = dict(size=11, color="#000000")

    # ── Overall figure layout ─────────────────────────────────────────────────
    chart_height = 320 * n_rows if not is_standardized else 480

    fig.update_layout(
        height=chart_height,
        paper_bgcolor="white",
        plot_bgcolor="#fafafa",
        margin=dict(t=60, b=40, l=60, r=20),
        font=dict(family="Arial, sans-serif", size=11,color="#000000"),
    )

    # Light gridlines and clean x-axis date formatting
    fig.update_xaxes(
        showgrid=True,
        gridcolor="#eeeeee",
        tickformat="%b %Y",
        tickangle=-30,
        tickfont=dict(color="#111111", size=11),
    )
    fig.update_yaxes(
        showgrid=True,
        gridcolor="#eeeeee",
        tickfont=dict(color="#111111", size=11),
    )

    st.plotly_chart(fig, width="stretch")

    # ── Footer note ───────────────────────────────────────────────────────────
    if is_standardized:
        st.caption("Values shown as z-scores (mean=0, sd=1). Each variable standardized independently across the full dataset.")
    elif is_gdp_deflated:
        st.caption("Values shown in 2026Q1 dollars, deflated using the GDP Implicit Price Deflator (BEA NIPA Table 1.1.9, Series A191RD, 2026Q1 base).")
    else:
        st.caption("Values shown in nominal USD. Source: U.S. Treasury Monthly Treasury Statement (MTS).")